  ('fire-eq-tech-moex-01936', 'fire-eq-tech', 'fire-eq-tech-moex-104-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '建築物裝設緊急廣播設備，有關廣播分區劃定，下列何者錯誤？', '["每一廣播分區不得超過一樓層", "室內安全梯或特別安全梯應垂直距離每15公尺單獨設定一廣播分區", "安全梯或特別安全梯之地下層部分，另設定一廣播分區", "挑空構造部分，所設揚聲器音壓符合規定時，得為一廣播分區"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "d267b2422afc", "answer_pdf_sha1": "2564ebe1eb47", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "402", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
