  ('fire-eq-tech-moex-01939', 'fire-eq-tech', 'fire-eq-tech-moex-104-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '有關倚靠型梯的敘述，依金屬製避難梯認可基準規定，下列何者錯誤？', '["在上方支撐點處，應裝設防止打滑及跌倒之安全裝置", "下端支撐點，應設置防止跌倒裝置", "如為可伸縮構造者，應裝設能防止使用時自動縮梯之安全裝置", "如為可折疊構造者，應裝設能防止使用時自動折疊之安全裝置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "d267b2422afc", "answer_pdf_sha1": "2564ebe1eb47", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "402", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
